// @ts-nocheck

function firstNonEmpty() {
  for (let i = 0; i < arguments.length; i++) {
    const value = arguments[i];
    if (value !== undefined && value !== null && String(value).trim() !== '') {
      return value;
    }
  }
  return '';
}

function onlyDigits(value) {
  return String(value || '').replace(/\D/g, '');
}

function getByPath(obj, path) {
  try {
    return path.split('.').reduce((cur, p) => {
      if (cur === undefined || cur === null) return '';
      return cur[p];
    }, obj) ?? '';
  } catch (e) {
    return '';
  }
}

function normalizeBrazilWhatsappPhone(value) {
  let raw = String(value || '');
  let digits = onlyDigits(raw.split('@')[0]);

  if (!digits) return '';

  digits = digits.replace(/^0+/, '');

  // Se veio sem DDI, assume Brasil.
  if (!digits.startsWith('55')) {
    if (digits.length === 10 || digits.length === 11) {
      digits = '55' + digits;
    }
  }

  // Regra validada:
  // 554588230845@s.whatsapp.net -> 5545988230845
  // 55 + DDD + 8 dígitos iniciando em 6/7/8/9 -> inserir nono dígito.
  if (digits.startsWith('55') && digits.length === 12) {
    const ddd = digits.slice(2, 4);
    const subscriber = digits.slice(4);

    if (/^[6-9]/.test(subscriber)) {
      digits = '55' + ddd + '9' + subscriber;
    }
  }

  return digits;
}

function getMessageText(message) {
  if (!message || typeof message !== 'object') return '';

  const orderCount = getByPath(message, 'orderMessage.itemCount');
  const orderFallback = orderCount ? 'Pedido/carrinho com ' + orderCount + ' itens' : '';

  return firstNonEmpty(
    getByPath(message, 'conversation'),
    getByPath(message, 'extendedTextMessage.text'),
    getByPath(message, 'imageMessage.caption'),
    getByPath(message, 'videoMessage.caption'),
    getByPath(message, 'documentMessage.caption'),
    getByPath(message, 'buttonsResponseMessage.selectedDisplayText'),
    getByPath(message, 'buttonsResponseMessage.selectedButtonId'),
    getByPath(message, 'listResponseMessage.title'),
    getByPath(message, 'listResponseMessage.singleSelectReply.selectedRowId'),
    getByPath(message, 'templateButtonReplyMessage.selectedDisplayText'),
    getByPath(message, 'templateButtonReplyMessage.selectedId'),
    getByPath(message, 'orderMessage.orderTitle'),
    orderFallback
  );
}

function detectMessageType(data, message) {
  const declared = firstNonEmpty(
    getByPath(data, 'messageType'),
    getByPath(data, 'type')
  );

  if (declared) {
    const d = String(declared).toLowerCase();

    if (d.includes('image')) return 'image';
    if (d.includes('audio')) return 'audio';
    if (d.includes('video')) return 'video';
    if (d.includes('document')) return 'document';
    if (d.includes('order')) return 'cart';
    if (d.includes('cart')) return 'cart';
    if (d.includes('location')) return 'location';
    if (d.includes('contact')) return 'contact';
    if (d.includes('conversation') || d.includes('text')) return 'text';
  }

  if (!message || typeof message !== 'object') return 'unknown';

  if (message.conversation || message.extendedTextMessage) return 'text';
  if (message.imageMessage) return 'image';
  if (message.audioMessage || message.pttMessage) return 'audio';
  if (message.videoMessage) return 'video';
  if (message.documentMessage) return 'document';
  if (message.orderMessage) return 'cart';
  if (message.locationMessage) return 'location';
  if (message.contactMessage || message.contactsArrayMessage) return 'contact';

  return 'unknown';
}

function toIsoTimestamp(value) {
  if (!value) return new Date().toISOString();

  if (typeof value === 'number') {
    if (value < 10000000000) {
      return new Date(value * 1000).toISOString();
    }

    return new Date(value).toISOString();
  }

  const parsed = new Date(value);
  if (!Number.isNaN(parsed.getTime())) return parsed.toISOString();

  return new Date().toISOString();
}

// Ponto principal da correção:
// o Webhook do n8n entrega a Evolution dentro de $json.body.
const envelope = $json || {};
const payload = envelope.body || envelope;

const data =
  payload.data ||
  payload.message ||
  (payload.messages && payload.messages[0]) ||
  payload;

const key = data.key || payload.key || {};
const message = data.message || payload.message || {};

const remoteJid = firstNonEmpty(
  key.remoteJid,
  key.remoteJidAlt,
  data.remoteJid,
  data.from,
  data.chatId,
  payload.remoteJid,
  payload.from,
  payload.chatId,
  data.sender,
  payload.sender
);

const fromMe = Boolean(
  key.fromMe !== undefined ? key.fromMe :
  data.fromMe !== undefined ? data.fromMe :
  payload.fromMe !== undefined ? payload.fromMe :
  false
);

const messageText = String(
  firstNonEmpty(
    getMessageText(message),
    data.text,
    payload.text,
    data.body,
    payload.body
  )
).trim();

const messageType = detectMessageType(data, message);

const pushName = String(firstNonEmpty(
  data.pushName,
  data.senderName,
  payload.pushName,
  payload.senderName,
  data.notifyName,
  'Cliente WhatsApp'
)).trim();

const phoneNormalized = normalizeBrazilWhatsappPhone(remoteJid);

const messageId = firstNonEmpty(
  key.id,
  data.id,
  payload.id,
  data.messageId,
  payload.messageId
);

const instance = firstNonEmpty(
  payload.instance,
  data.instance,
  payload.instanceName,
  data.instanceName,
  'julia'
);

const event = firstNonEmpty(
  payload.event,
  data.event,
  ''
);

let mediaUrl = '';
let mediaKey = null;

if (message.audioMessage || message.pttMessage) {
  const audioMsg = message.audioMessage || message.pttMessage;
  mediaUrl = firstNonEmpty(audioMsg.url, audioMsg.directPath);
  mediaKey = key;
}

if (message.imageMessage) {
  mediaUrl = firstNonEmpty(message.imageMessage.url, message.imageMessage.directPath);
  mediaKey = key;
}

if (message.videoMessage) {
  mediaUrl = firstNonEmpty(message.videoMessage.url, message.videoMessage.directPath);
  mediaKey = key;
}

if (message.documentMessage) {
  mediaUrl = firstNonEmpty(message.documentMessage.url, message.documentMessage.directPath);
  mediaKey = key;
}

let skip = false;
let reason = '';

if (fromMe) {
  skip = true;
  reason = 'fromMe';
}

if (String(remoteJid || '').includes('@g.us')) {
  skip = true;
  reason = 'group';
}

if (String(remoteJid || '').includes('status@broadcast')) {
  skip = true;
  reason = 'status';
}

if (!phoneNormalized) {
  skip = true;
  reason = reason || 'phone_not_found';
}

const textNorm = messageText
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .trim();

const rawPayload = {
  event,
  instance,
  key,
  pushName,
  message_type: messageType,
  messageTimestamp: firstNonEmpty(
    data.messageTimestamp,
    payload.messageTimestamp,
    data.timestamp,
    payload.timestamp
  )
};

return [{
  json: {
    phone_normalized: phoneNormalized,
    push_name: pushName,
    instance,
    message_id: messageId,
    message_type: messageType,
    message_text: messageText,
    message_text_normalized: textNorm,
    message_timestamp: toIsoTimestamp(firstNonEmpty(
      data.messageTimestamp,
      payload.messageTimestamp,
      data.timestamp,
      payload.timestamp
    )),
    media_url: mediaUrl,
    media_key_json: mediaKey || null,
    raw_payload: rawPayload,
    full_payload: payload,
    remote_jid: remoteJid,
    external_contact_id: remoteJid,
    channel: 'whatsapp',
    from_me: fromMe,
    event,
    skip
  }
}];

// @ts-nocheck
const norm = $('NORMALIZA PAYLOAD WHATSAPP | S6').item.json;
const bufRaw = $json.value || $json.propertyName || '';

let existing = [];
try {
  if (bufRaw && typeof bufRaw === 'string' && bufRaw.startsWith('[')) {
    existing = JSON.parse(bufRaw) || [];
  }
} catch (_) {}

const newMsg = {
  message_id: norm.message_id,
  message_text: norm.message_text || '',
  message_type: norm.message_type || 'text',
  media_url: norm.media_url || '',
  ts: Date.now()
};

existing.push(newMsg);

// Keep last 10 messages max
if (existing.length > 10) existing = existing.slice(-10);

return [{ json: { ...norm, buffer: existing, buffer_json: JSON.stringify(existing) } }];

// @ts-nocheck
// Monta contexto final a partir do buffer acumulado
const norm = $('NORMALIZA PAYLOAD WHATSAPP | S6').item.json;
let buffer = [];
try {
const raw = $json.value || $json.propertyName || '';
  if (raw && typeof raw === 'string' && raw.startsWith('[')) {
    buffer = JSON.parse(raw) || [];
  }
} catch (_) {}

if (buffer.length === 0) {
  buffer = [{
    message_id: norm.message_id || '',
    message_text: norm.message_text || '',
    message_type: norm.message_type || 'text',
    media_url: norm.media_url || '',
    ts: Date.now()
  }];
}

// Merge text messages
const mergedText = buffer
  .map(m => (m.message_text || '').trim())
  .filter(Boolean)
  .join('\n');

const mergedTextNorm = mergedText.toLowerCase()
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '').trim();

// Detect special types in buffer (priority: cart > audio > image > text)
const hasCart = buffer.some(m => m.message_type === 'cart');
const hasAudio = buffer.some(m => m.message_type === 'audio');
const hasImage = buffer.some(m => m.message_type === 'image');

let effectiveType = 'text';
if (hasCart) effectiveType = 'cart';
else if (hasAudio) effectiveType = 'audio';
else if (hasImage) effectiveType = 'image';
else if (buffer.length === 1) effectiveType = norm.message_type;

// Get media URL/key from the relevant buffer message
const mediaMsg = buffer.find(m => ['audio', 'image', 'video'].includes(m.message_type));
const mediaUrl = mediaMsg?.media_url || norm.media_url || '';

return [{
  json: {
    ...norm,
    message_text: mergedText || norm.message_text || '',
    message_text_normalized: mergedTextNorm || norm.message_text_normalized || '',
    message_type: effectiveType,
    buffer_count: buffer.length,
    buffer_messages: buffer,
    has_audio: hasAudio,
    has_image: hasImage,
    has_cart: hasCart,
    media_url: mediaUrl,
    transcription: null,
    visual_description: null
  }
}];

// @ts-nocheck
// Prepara parâmetros para download de áudio via Evolution
const norm = $('CODE: MONTA CONTEXTO | S6').item.json;
const fullPayload = norm.full_payload || {};
const data = fullPayload.data || fullPayload;
const key = data.key || {};

// Tenta extrair URL do media direto do payload
const message = data.message || {};
const audioMsg = message.audioMessage || message.pttMessage || {};
const directUrl = audioMsg.url || norm.media_url || '';

return [{
  json: {
    ...norm,
    audio_direct_url: directUrl,
    evolution_key: key,
    instance: norm.instance || '',
    needs_evolution_download: !directUrl || directUrl.includes('whatsapp.net')
  }
}];

// @ts-nocheck
// Converte base64 do Evolution para binary data do n8n
const norm = $('CODE: MONTA CONTEXTO | S6').item.json;
const evolutionResp = $json;

const b64 = evolutionResp.base64 || evolutionResp.media || evolutionResp.data || '';

if (!b64 || evolutionResp.error) {
  // Evolution download failed — return flag for fallback
  return [{ json: { ...norm, audio_b64_missing: true, audio_error: evolutionResp.error || 'No base64 from Evolution' } }];
}

const ext = evolutionResp.ext || evolutionResp.mediaType?.split('/')[1] || 'ogg';
const mimeMap = { ogg: 'audio/ogg', mp4: 'audio/mp4', mp3: 'audio/mpeg', m4a: 'audio/mp4', wav: 'audio/wav', opus: 'audio/ogg' };
const mime = mimeMap[ext] || 'audio/ogg';

const buf = Buffer.from(b64, 'base64');
const binaryData = await $helpers.prepareBinaryData(buf, 'audio.' + ext, mime);

return [{
  json: { ...norm, audio_mime: mime, audio_ext: ext, audio_size: buf.length, audio_b64_missing: false },
  binary: { data: binaryData }
}];

// @ts-nocheck
// Merge transcription result. Handles success and all failure modes.
const norm = $('CODE: MONTA CONTEXTO | S6').item.json;
const current = $json;

// Check if previous steps failed
if (norm.audio_b64_missing) {
  return [{ json: {
    ...norm,
    message_text: norm.message_text || '🎙️ [Áudio recebido — não foi possível transcrever]',
    transcription: null,
    audio_processed: false,
    agent_note: 'AUDIO_DOWNLOAD_FAILED'
  }}];
}

// Check OpenAI transcription result
const transcription = current.text || current.transcription || '';

if (!transcription && current.error) {
  return [{ json: {
    ...norm,
    message_text: norm.message_text || '🎙️ [Áudio recebido — transcrição indisponível]',
    transcription: null,
    audio_processed: false,
    agent_note: 'TRANSCRIPTION_FAILED'
  }}];
}

return [{ json: {
  ...norm,
  message_text: transcription || norm.message_text || '',
  transcription: transcription,
  audio_processed: true,
  agent_note: transcription ? 'AUDIO_TRANSCRIBED' : 'AUDIO_EMPTY'
}}];

// @ts-nocheck
// Extrai URL da imagem do payload Evolution
const norm = $('CODE: MONTA CONTEXTO | S6').item.json;
const fullPayload = norm.full_payload || {};
const data = fullPayload.data || fullPayload;
const message = data.message || {};
const imgMsg = message.imageMessage || {};

// Use direct URL if available and not ephemeral whatsapp URL
let imageUrl = imgMsg.url || norm.media_url || '';

// If it's an ephemeral WA URL, use thumbnail base64 as data URL fallback
if (!imageUrl || imageUrl.includes('whatsapp.net') || imageUrl.includes('enc')) {
  const thumb = imgMsg.jpegThumbnail;
  if (thumb) {
    imageUrl = 'data:image/jpeg;base64,' + thumb;
  }
}

return [{
  json: {
    ...norm,
    image_url: imageUrl,
    image_caption: imgMsg.caption || norm.message_text || ''
  }
}];

// @ts-nocheck
// Merge image vision result
const norm = $('CODE: MONTA CONTEXTO | S6').item.json;
const current = $json;

let visualDesc = '';
try {
  visualDesc = current.choices?.[0]?.message?.content || current.error?.message || '';
} catch (_) { visualDesc = ''; }

if (!visualDesc || current.error) {
  return [{ json: {
    ...norm,
    visual_description: null,
    image_processed: false,
    agent_note: (norm.agent_note || '') + ' IMAGE_ANALYSIS_FAILED'
  }}];
}

// Detect payment receipt
const isPaymentReceipt = /comprovante|pagamento|pix|transferencia|receipt/i.test(visualDesc);

return [{ json: {
  ...norm,
  visual_description: visualDesc,
  image_processed: true,
  is_payment_receipt: isPaymentReceipt,
  message_text: norm.message_text || ('[Imagem: ' + visualDesc.substring(0, 100) + ']'),
  agent_note: (norm.agent_note || '') + (isPaymentReceipt ? ' PAYMENT_RECEIPT' : ' IMAGE_REFERENCE')
}}];

// @ts-nocheck

/**
 * CODE: PREPARA PROMPT | S6
 * Versão revisada — Flora Dia das Mães
 *
 * Objetivo:
 * - Preparar system_prompt + user_context para o agente Flora.
 * - Manter compatibilidade com o workflow atual.
 * - Incorporar regras fortes das versões testadas:
 *   agent_messages, escolha de produto após opções, search_catalog técnico,
 *   create_order_draft, checkout, carrinho WhatsApp e comprovante.
 */

function clean(value) {
  if (value === undefined || value === null) return '';
  return String(value).trim();
}

function safeString(value, fallback = '') {
  const v = clean(value);
  return v || fallback;
}

function asArray(value) {
  return Array.isArray(value) ? value : [];
}

function truncate(value, max = 240) {
  const text = clean(value);
  if (!text) return '';
  return text.length > max ? text.slice(0, max - 1) + '…' : text;
}

function normalizeText(value) {
  return clean(value)
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .trim();
}

function formatCurrencyBR(value) {
  if (value === undefined || value === null || value === '') return '';
  const num = Number(value);
  if (!Number.isFinite(num)) return clean(value);
  return num.toLocaleString('pt-BR', {
    style: 'currency',
    currency: 'BRL'
  });
}

function safeJsonPreview(value, max = 900) {
  try {
    const text = JSON.stringify(value || {}, null, 2);
    return truncate(text, max);
  } catch (e) {
    return '';
  }
}

function getVar(name, fallback = '') {
  try {
    if (typeof $vars !== 'undefined' && $vars && $vars[name] !== undefined && $vars[name] !== null) {
      return String($vars[name]);
    }
  } catch (e) {}
  return fallback;
}

const norm = $('CODE: MONTA CONTEXTO | S6').item.json || {};
const rawCtx = $json || {};
const ctx = Array.isArray(rawCtx) ? (rawCtx[0] || {}) : rawCtx;

const customer = ctx.customer || {};
const conversation = ctx.conversation || {};
const recentMessages = asArray(ctx.recent_messages);
const currentOrder = ctx.current_order || {};
const currentItems = asArray(ctx.current_order_items);

const phone = safeString(norm.phone_normalized);
const customerName = safeString(
  customer.full_name || customer.name || norm.push_name,
  'cliente'
);

const isExisting = Boolean(
  customer.is_existing_customer ||
  customer.id ||
  ctx.customer_id
);

const convStage = safeString(
  conversation.stage || ctx.stage,
  'new'
);

const humanLock = Boolean(
  conversation.human_takeover ||
  ctx.human_takeover ||
  norm.human_lock
);

const conversationId =
  ctx.conversation_id ||
  conversation.id ||
  norm.conversation_id ||
  null;

const customerId =
  ctx.customer_id ||
  customer.id ||
  norm.customer_id ||
  null;

const catalogBase = String(
'https://flordoestudante.vercel.app')
).replace(/\/+$/, '');

const currentOrderId =
  currentOrder.order_id ||
  currentOrder.id ||
  ctx.current_order_id ||
  norm.current_order_id ||
  null;

const currentOrderCode =
  currentOrder.public_code ||
  currentOrder.order_public_code ||
  ctx.current_order_public_code ||
  norm.current_order_public_code ||
  null;

const nowBR = new Date().toLocaleString('pt-BR', {
  timeZone: 'America/Sao_Paulo',
  dateStyle: 'short',
  timeStyle: 'short'
});

const messageType = safeString(norm.message_type, 'text');
const messageNorm = normalizeText(norm.message_text || '');
const agentNote = safeString(norm.agent_note);

const hasAudio = Boolean(norm.has_audio || norm.transcription);
const hasImage = Boolean(norm.has_image || norm.visual_description);
const hasCart = Boolean(norm.has_cart || messageType === 'cart');
const isPaymentReceipt = Boolean(
  norm.is_payment_receipt ||
  /PAYMENT_RECEIPT/i.test(agentNote)
);

const historyText = recentMessages
  .slice(-10)
  .map((m) => {
    const senderType = safeString(m.sender_type || m.role || m.sender);
    const who =
      senderType === 'agent' || senderType === 'assistant'
        ? '🤖 Agente'
        : '👤 Cliente';

    const body = truncate(
      m.body ||
      m.content ||
      m.message ||
      m.text ||
      '',
      260
    );

    if (!body) return '';
    return `${who}: ${body}`;
  })
  .filter(Boolean)
  .join('\n');

let orderContext = '';

if (currentOrderId) {
  const status = safeString(currentOrder.status, 'draft');
  const total =
    currentOrder.total_amount ||
    currentOrder.current_order_total_amount ||
    currentOrder.amount_total ||
    '';

  const fulfillment =
    currentOrder.fulfillment_type ||
    currentOrder.delivery_type ||
    currentOrder.shipping_method ||
    '';

  orderContext += `Pedido atual: ${currentOrderCode || currentOrderId} (${status})\n`;

  if (total !== '') {
    orderContext += `Total atual: ${formatCurrencyBR(total)}\n`;
  }

  if (fulfillment) {
    orderContext += `Entrega/retirada: ${fulfillment}\n`;
  }

  const desiredDate =
    currentOrder.desired_fulfillment_date ||
    currentOrder.desired_date ||
    currentOrder.delivery_date ||
    '';

  const desiredPeriod =
    currentOrder.desired_fulfillment_period ||
    currentOrder.delivery_period ||
    '';

  if (desiredDate || desiredPeriod) {
    orderContext += `Data/período desejado: ${[desiredDate, desiredPeriod].filter(Boolean).join(' — ')}\n`;
  }

  const recipientName =
    currentOrder.recipient_name ||
    currentOrder.delivery_recipient_name ||
    '';

  if (recipientName) {
    orderContext += `Destinatária(o): ${recipientName}\n`;
  }

  const giftMessage =
    currentOrder.gift_message ||
    currentOrder.card_message ||
    '';

  if (giftMessage) {
    orderContext += `Mensagem do cartão: ${truncate(giftMessage, 220)}\n`;
  }

  if (currentItems.length > 0) {
    const itemsText = currentItems
      .map((i) => {
        const name =
          i.product_name ||
          i.name ||
          i.item_name ||
          i.title ||
          'item';

        const quantity = i.quantity || i.qty || 1;
        return `${name} x${quantity}`;
      })
      .join(', ');

    orderContext += `Itens: ${itemsText}\n`;
  }
}

let enrichedInput = safeString(norm.message_text);

if (norm.transcription) {
  enrichedInput = `[Áudio transcrito]: ${norm.transcription}`;
}

if (norm.visual_description) {
  enrichedInput += `${enrichedInput ? '\n' : ''}[Imagem analisada]: ${norm.visual_description}`;
}

if (isPaymentReceipt) {
  enrichedInput += `${enrichedInput ? '\n' : ''}[SISTEMA: Cliente enviou imagem que parece ser comprovante de pagamento. Não confirme pagamento como aprovado; apenas acuse recebimento e siga o fluxo de conferência/checkout.]`;
}

if (hasCart) {
  enrichedInput += `${enrichedInput ? '\n' : ''}[SISTEMA: Cliente enviou um carrinho/pedido do WhatsApp. Priorize action=parse_whatsapp_cart se ainda não houver pedido rascunho estruturado.]`;
}

if (!enrichedInput && hasAudio) {
  enrichedInput = '[SISTEMA: Cliente enviou áudio, mas a transcrição não está disponível. Peça para reenviar em texto ou áudio curto.]';
}

if (!enrichedInput && hasImage) {
  enrichedInput = '[SISTEMA: Cliente enviou imagem, mas a análise visual não está disponível. Peça uma breve descrição do que deseja.]';
}

const customerContextExtra = safeJsonPreview({
  customer: {
    id: customerId,
    name: customerName,
    is_existing: isExisting,
    phone
  },
  conversation: {
    id: conversationId,
    stage: convStage,
    human_lock: humanLock
  },
  message: {
    type: messageType,
    has_audio: hasAudio,
    has_image: hasImage,
    has_cart: hasCart,
    is_payment_receipt: isPaymentReceipt
  },
  current_order: currentOrderId
    ? {
        id: currentOrderId,
        public_code: currentOrderCode,
        status: currentOrder.status || '',
        fulfillment_type: currentOrder.fulfillment_type || '',
        items_count: currentItems.length
      }
    : null
}, 1200);

const SYSTEM_PROMPT = `Você é Flora, assistente virtual da Flor do Estudante 🌸 — floricultura especializada em flores, arranjos, buquês, cestas e presentes.

CONTEXTO DA CAMPANHA:
- Estamos em campanha do Dia das Mães.
- Data/hora atual no Brasil: ${nowBR}.
- Sua missão é ajudar o cliente a escolher um presente bonito, montar o pedido e conduzir até checkout/pagamento ou atendimento humano quando necessário.
- O tom deve ser acolhedor, delicado, consultivo, objetivo e humano.
- Use emojis com moderação: 🌸, 💐, 🌷, ❤️.

IDENTIDADE:
- Seu nome é Flora.
- Você atende pela Flor do Estudante.
- Você não deve dizer que é IA, robô ou modelo.
- Não saia do personagem.
- Não use linguagem fria, burocrática ou robótica.

REGRAS COMERCIAIS CRÍTICAS:
1. Priorize o Dia das Mães quando fizer sentido.
2. Se a ocasião não estiver clara, pergunte delicadamente.
3. Nunca invente produtos, preços, estoque, frete, prazo ou disponibilidade.
4. Use somente dados que vierem do catálogo/workflow/contexto.
5. Quando o cliente pedir opções, flores específicas, orçamento ou categoria clara, use action=search_catalog.
6. Quando action=search_catalog, sua agent_reply deve ser só uma frase curta de transição, sem lista de produtos e sem pergunta final.
7. Não negue disponibilidade sem consulta. Quando houver intenção clara, avance para montar o pedido: "posso montar esse pedido para você".
8. Conduza a venda até pedido rascunho, dados essenciais e checkout sempre que possível.
9. Não transfira para humano apenas porque o cliente quer fechar, pagar ou escolher produto.
10. Acione humano se o cliente pedir atendente, houver reclamação, dúvida operacional não coberta, falha técnica, entrega excepcional, negociação especial ou risco de promessa indevida.
11. Faça uma pergunta principal por resposta.
12. Preserve dados já informados. Não peça novamente o que já está no contexto.

