const agentCtx = $('CODE: DETECTA ESCOLHA DE PRODUTO | S6').first().json || {};
const inputItems = $input.all();
const catalogBase = String('https://flordoestudante.vercel.app').replace(/\/+$/, '');

let products = [];

for (const item of inputItems) {
  const d = item.json;

  if (!d || d.error) continue;

  if (Array.isArray(d)) {
    products.push(...d);
    continue;
  }

  if (Array.isArray(d.items)) {
    products.push(...d.items);
    continue;
  }

  if (Array.isArray(d.products)) {
    products.push(...d.products);
    continue;
  }

  if (Array.isArray(d.catalog_items)) {
    products.push(...d.catalog_items);
    continue;
  }

  if (d.name || d.slug || d.item_id || d.id) {
    products.push(d);
  }
}

const seen = new Set();

products = products.filter((p) => {
  const key = String(p.item_id || p.id || p.slug || p.name || '');
  if (!key || seen.has(key)) return false;
  seen.add(key);
  return true;
});

products.sort((a, b) => {
  const scoreA = Number(a.match_score || 0);
  const scoreB = Number(b.match_score || 0);

  if (scoreB !== scoreA) return scoreB - scoreA;

  const imgA = a.cover_image_url ? 1 : 0;
  const imgB = b.cover_image_url ? 1 : 0;

  if (imgB !== imgA) return imgB - imgA;

  return Number(a.price || 999999) - Number(b.price || 999999);
});

const topProducts = products.slice(0, 3);

const sourceText = String(
  $('NORMALIZA PAYLOAD WHATSAPP | S6').first().json.message_text_normalized ||
  $('NORMALIZA PAYLOAD WHATSAPP | S6').first().json.message_text ||
  ''
)
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '');

function normalizeText(value) {
  return String(value || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/-/g, ' ')
    .trim();
}

function productMatchesMessage(product) {
  const name = normalizeText(product.name);
  const slug = normalizeText(product.slug);

  if (!name && !slug) return false;

  return (
    sourceText.includes(name) ||
    sourceText.includes(slug) ||
    (name.includes('cesta') && sourceText.includes('cesta')) ||
    (name.includes('cafe') && sourceText.includes('cafe')) ||
    (name.includes('rosas') && sourceText.includes('rosas')) ||
    (name.includes('girassol') && sourceText.includes('girassol'))
  );
}

function formatPrice(value) {
  const num = Number(value || 0);
  if (!num) return '';
  return num.toLocaleString('pt-BR', {
    style: 'currency',
    currency: 'BRL'
  });
}

function clean(value) {
  if (value === undefined || value === null) return '';
  return String(value).trim();
}

function truncate(value, max = 900) {
  const text = clean(value);
  if (!text) return '';
  return text.length > max ? text.slice(0, max - 1) + '…' : text;
}

function productUrl(product) {
  if (!product || !product.slug) return catalogBase;
  return `${catalogBase}/produto/${product.slug}`;
}

function productCaption(product, index) {
  const emojis = ['🌸', '💐', '🌷'];
  const emoji = emojis[index] || '🌸';

  const name = clean(product.name || 'Produto');
  const price = formatPrice(product.price);

  const shortDescription = clean(product.short_description || '');
  const fullDescription = clean(product.description || '');

  // Prioriza short_description quando houver
  // Se não houver, usa description resumida
  const mainDescription = shortDescription || fullDescription;

  const categoryName = clean(product.category_name || '');
  const availability =
    product.requires_confirmation === true
      ? 'Disponibilidade sujeita à confirmação'
      : '';

  const url = productUrl(product);

  const lines = [
    `${emoji} *${name}*`,
    price ? `💰 *${price}*` : '',
    categoryName ? `📂 ${categoryName}` : '',
    mainDescription ? `📝 ${truncate(mainDescription, 220)}` : '',
    availability ? `ℹ️ ${availability}` : '',
    `🔗 ${url}`
  ].filter(Boolean);

  return lines.join('\n');
}

const selectedProduct = topProducts.find(productMatchesMessage) || topProducts[0] || null;

/**
 * Caminho de compra direta:
 * Se o cliente escolheu um produto depois da busca, mantém a lógica de pedido rascunho.
 */
if (agentCtx.force_create_order_after_catalog && selectedProduct) {
  const price = Number(selectedProduct.price || 0);

  return [
    {
      json: {
        ...agentCtx,

        agent_action: 'create_order_draft',
        agent_stage: 'pedido_em_montagem',

        selected_product: selectedProduct,
        selected_product_id: selectedProduct.item_id || selectedProduct.id,
        selected_product_name: selectedProduct.name,

        catalog_results: [selectedProduct],
        all_catalog_results: products,

        has_catalog_images: Boolean(selectedProduct.cover_image_url),
        first_image_product: selectedProduct.cover_image_url ? selectedProduct : null,

        order_data: {
          ...(agentCtx.order_data || {}),
          occasion: agentCtx.occasion_filter || 'dia_das_maes',
          source: 'whatsapp_agent',
          is_gift: true,
          selected_product: selectedProduct,
          items: [
            {
              item_type: selectedProduct.item_type || 'product',
              item_id: selectedProduct.item_id || selectedProduct.id,
              product_id: selectedProduct.item_type === 'product' ? (selectedProduct.item_id || selectedProduct.id) : (selectedProduct.item_id || selectedProduct.id),
              addon_id: selectedProduct.item_type === 'addon' ? (selectedProduct.item_id || selectedProduct.id) : null,
              name: selectedProduct.name,
              product_name: selectedProduct.name,
              slug: selectedProduct.slug,
              quantity: 1,
              unit_price: price,
              total_price: price
            }
          ]
        },

        agent_reply: `Perfeito, vou montar o pedido da *${selectedProduct.name}* para o Dia das Mães 🌸\n\nPara continuar, você prefere *entrega* ou *retirada na loja*?`,
        agent_messages: [
          `Perfeito, vou montar o pedido da *${selectedProduct.name}* para o Dia das Mães 🌸\n\nPara continuar, você prefere *entrega* ou *retirada na loja*?`
        ]
      }
    }
  ];
}

/**
 * Sem produtos encontrados.
 */
if (topProducts.length === 0) {
  const fallbackReply = 'Não encontrei uma opção exata para essa busca agora, mas você pode consultar mais opções em nosso catálogo 🌸\n\n🔗 ' + catalogBase;

  return [
    {
      json: {
        ...agentCtx,

        agent_action: agentCtx.agent_action || 'ask_info',
        agent_stage: agentCtx.agent_stage || 'buscando_opcoes',

        agent_reply: fallbackReply,
        agent_messages: [fallbackReply],

        catalog_results: [],
        all_catalog_results: products,

        catalog_intro_message: '',
        catalog_final_message: fallbackReply,
        catalog_media_options: [],

        has_catalog_images: false,
        first_image_product: null,

        catalog_base: catalogBase,
        catalog_count: 0
      }
    }
  ];
}

/**
 * Caminho normal de apresentação de opções:
 * O texto de opções NÃO fica mais no agent_reply.
 * O agent_reply final será apenas a pergunta final.
 */
const imageProducts = topProducts.filter((p) => p.cover_image_url);

const catalogMediaOptions = imageProducts.map((p, index) => {
  return {
    index,
    id: p.item_id || p.id || '',
    name: p.name || 'Produto',
    slug: p.slug || '',
    media: p.cover_image_url || '',
    caption: productCaption(p, index),
    url: productUrl(p),
    price: p.price || null
  };
});

const introMessage =
  'Claro, vou te mostrar algumas opções lindas para o Dia das Mães 🌸';

const finalMessage =
  `Temos nosso catálogo online caso queira conferir mais opções também:\n${catalogBase}\n\nGostou de alguma dessas?`;

const textFallbackLines = topProducts.map((p, index) => productCaption(p, index));
const textFallbackReply =
  `${introMessage}\n\n${textFallbackLines.join('\n\n')}\n\n${finalMessage}`;

return [
  {
    json: {
      ...agentCtx,

      agent_action: 'search_catalog',
      agent_stage: 'apresentando_opcoes',

      /**
       * Importante:
       * agent_reply agora é só a mensagem final,
       * porque introdução e imagens serão enviadas antes por nodes específicos.
       */
      agent_reply: catalogMediaOptions.length > 0 ? finalMessage : textFallbackReply,
      agent_messages: [catalogMediaOptions.length > 0 ? finalMessage : textFallbackReply],

      catalog_intro_message: introMessage,
      catalog_final_message: finalMessage,
      catalog_text_fallback_reply: textFallbackReply,

      catalog_results: topProducts,
      all_catalog_results: products,
      catalog_media_options: catalogMediaOptions,

      has_catalog_images: catalogMediaOptions.length > 0,
      first_image_product: catalogMediaOptions.length > 0 ? imageProducts[0] : null,

      catalog_base: catalogBase,
      catalog_count: products.length,

      send_catalog_as_media_sequence: catalogMediaOptions.length > 0
    }
  }
];

// @ts-nocheck
const ctx = $json || {};

function money(value) {
  return Number(value || 0).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
}

const selected = ctx.selected_product || (Array.isArray(ctx.catalog_results) ? ctx.catalog_results[0] : null) || ctx.first_image_product || null;

if (!selected) {
  return [{
    json: {
      ...ctx,
      agent_action: 'ask_info',
      agent_stage: 'buscando_opcoes',
      agent_reply: 'Perfeito! Só preciso confirmar qual produto você escolheu para montar o pedido 🌸',
      order_data: ctx.order_data || {},
      suggested_addons: [],
      can_create_order: false
    }
  }];
}

const allResults = Array.isArray(ctx.all_catalog_results) ? ctx.all_catalog_results : Array.isArray(ctx.catalog_results) ? ctx.catalog_results : [];

const suggestedAddons = allResults
  .filter((item) => {
    if (!item || item.item_type !== 'addon' || !item.name) return false;
    const name = String(item.name).toLowerCase();
    return name.includes('cart') || name.includes('chocolate') || name.includes('vela') || name.includes('pelúcia') || name.includes('pelucia') || name.includes('urso') || name.includes('balão') || name.includes('balao');
  })
  .slice(0, 3)
  .map((item) => ({
    item_type: item.item_type || 'addon',
    item_id: item.item_id || item.id,
    addon_id: item.item_id || item.id,
    name: item.name,
    slug: item.slug,
    quantity: 1,
    unit_price: Number(item.price || 0),
    total_price: Number(item.price || 0),
    short_description: item.short_description || item.description || ''
  }));

const unitPrice = Number(selected.price || 0);

const primaryItem = {
  item_type: selected.item_type || 'product',
  item_id: selected.item_id || selected.id,
  product_id: selected.item_type === 'product' ? (selected.item_id || selected.id) : null,
  addon_id: selected.item_type === 'addon' ? (selected.item_id || selected.id) : null,
  name: selected.name,
  slug: selected.slug,
  quantity: 1,
  unit_price: unitPrice,
  total_price: unitPrice,
  short_description: selected.short_description || selected.description || ''
};

const orderData = {
  ...(ctx.order_data || {}),
  occasion: ctx.order_data?.occasion || ctx.occasion_filter || 'dia_das_maes',
  is_gift: ctx.order_data?.is_gift ?? true,
  fulfillment_type: ctx.order_data?.fulfillment_type || null,
  items: [primaryItem],
  suggested_addons: suggestedAddons,
  selected_product: {
    id: selected.id,
    item_id: selected.item_id || selected.id,
    item_type: selected.item_type,
    name: selected.name,
    slug: selected.slug,
    price: unitPrice,
    cover_image_url: selected.cover_image_url || ''
  }
};

return [{
  json: {
    ...ctx,
    agent_action: 'create_order_draft',
    agent_stage: 'pedido_em_montagem',
    selected_product: selected,
    selected_product_id: selected.item_id || selected.id,
    selected_product_name: selected.name,
    order_data: orderData,
    suggested_addons: suggestedAddons,
    can_create_order: true,
    order_summary_preview: {
      product_name: selected.name,
      product_price: money(unitPrice),
      suggested_addons: suggestedAddons.map(a => ({
        name: a.name,
        price: money(a.unit_price)
      }))
    }
  }
}];

