={{ JSON.stringify((() => {
  const od = $json.order_data || {};

  function clean(value) {
    if (value === undefined || value === null) return '';
    return String(value).trim();
  }

  function normalizeDate(value) {
    const v = clean(value);
    if (!v) return null;

    // já está em YYYY-MM-DD
    if (/^\d{4}-\d{2}-\d{2}$/.test(v)) return v;

    // dd/mm/yyyy
    const br = v.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
    if (br) {
      const dd = br[1].padStart(2, '0');
      const mm = br[2].padStart(2, '0');
      const yyyy = br[3];
      return `${yyyy}-${mm}-${dd}`;
    }

    return null;
  }

  function normalizeItem(item) {
    item = item || {};

    const productId = clean(
      item.product_id ||
      item.item_id ||
      item.id ||
      item.productId
    );

    const productName = clean(
      item.product_name ||
      item.name ||
      item.title ||
      item.productName
    );

    const unitPriceRaw =
      item.unit_price ??
      item.price ??
      item.sale_price ??
      item.final_price ??
      item.amount ??
      0;

    const quantityRaw =
      item.quantity ??
      item.qty ??
      1;

    const unitPrice = Number(
      String(unitPriceRaw).replace(',', '.').replace(/[^\d.]/g, '')
    );

    const quantity = Number.parseInt(quantityRaw, 10) || 1;

    if (!productId && !productName) return null;
    if (!Number.isFinite(unitPrice) || unitPrice <= 0) return null;

    return {
      product_id: productId || '',
      product_name: productName || 'Produto',
      unit_price: unitPrice,
      quantity
    };
  }

  const selected =
    $json.selected_product ||
    od.selected_product ||
    $json.product ||
    $json.catalog_product ||
    {};

  let items = [];

  if (Array.isArray(od.items) && od.items.length > 0) {
    items = od.items.map(normalizeItem).filter(Boolean);
  }

  if (items.length === 0 && Array.isArray(od.add_items) && od.add_items.length > 0) {
    items = od.add_items.map(normalizeItem).filter(Boolean);
  }

  if (items.length === 0 && selected && Object.keys(selected).length > 0) {
    const item = normalizeItem(selected);
    if (item) items = [item];
  }

  return {
    p_customer_id: $json.customer_id || null,
    p_conversation_id: $json.conversation_id || null,
    p_fulfillment_type: od.fulfillment_type || 'pickup',
    p_occasion: od.occasion || $json.occasion_filter || 'dia_das_maes',
    p_items: items,
    p_recipient_name: od.recipient_name || null,
    p_is_gift: od.is_gift ?? true,
    p_gift_message: od.gift_message || null,
    p_desired_date: normalizeDate(od.desired_date),
    p_desired_period: od.desired_period || null,
    p_notes: od.notes || null
  };
})()) }}

