// @ts-nocheck

const ctx = $('CODE: PREPARA ORDER DRAFT | S6').first().json || {};
const res = $json || {};

function money(value) {
  const n = Number(value || 0);
  return n.toLocaleString('pt-BR', {
    style: 'currency',
    currency: 'BRL'
  });
}

function clean(value) {
  if (value === undefined || value === null) return '';
  return String(value).trim();
}

const selected = ctx.selected_product || ctx.order_data?.selected_product || {};
const addons = Array.isArray(ctx.suggested_addons) ? ctx.suggested_addons : [];

const ok = res.ok === true;
const orderId =
  res.order_id ||
  res.id ||
  res.order?.id ||
  ctx.order_id ||
  ctx.current_order_id ||
  null;

const publicCode =
  res.public_code ||
  res.order_public_code ||
  res.order?.public_code ||
  ctx.public_code ||
  ctx.current_order_public_code ||
  null;

const productName =
  selected.name ||
  selected.product_name ||
  ctx.selected_product_name ||
  ctx.order_data?.items?.[0]?.product_name ||
  'esse produto';

const productPrice =
  selected.price ||
  selected.unit_price ||
  ctx.order_data?.items?.[0]?.unit_price ||
  res.total ||
  '';

let reply = '';

if (!ok || !orderId) {
  reply = `Perfeito, encontrei o produto para você 🌸 Antes de montar o pedido, você prefere *entrega* ou *retirada na loja*?`;

  return [
    {
      json: {
        ...ctx,
        ...res,
        order_create_ok: false,
        order_create_error: res.error || 'CREATE_ORDER_DRAFT_FAILED_OR_EMPTY_ORDER_ID',
        agent_action: 'ask_info',
        agent_stage: 'coletando_entrega_ou_retirada',
        agent_reply: reply,
        agent_messages: [reply],
        order_id: orderId,
        current_order_id: orderId,
        public_code: publicCode,
        current_order_public_code: publicCode,
        order_data: {
          ...(ctx.order_data || {}),
          order_id: orderId,
          public_code: publicCode
        },
        suggested_addons: addons,
        selected_product: selected
      }
    }
  ];
}

let addonText = '';

if (addons.length > 0) {
  const addonList = addons
    .slice(0, 3)
    .map((a) => `*${a.name}* (${money(a.unit_price || a.price)})`)
    .join(', ');

  addonText = `\n\nSe quiser deixar o presente ainda mais especial, também posso incluir ${addonList}.`;
}

const priceText = productPrice ? ` — ${money(productPrice)}` : '';

reply = [
  `Perfeito! Já montei o pedido da *${productName}*${priceText} para o Dia das Mães 🌸`,
  addonText,
  `\n\nAgora me diga: você prefere *entrega* ou *retirada na loja*?`
].join('');

return [
  {
    json: {
      ...ctx,
      ...res,

      order_create_ok: true,

      order_id: orderId,
      current_order_id: orderId,

      public_code: publicCode,
      current_order_public_code: publicCode,

      agent_action: 'ask_info',
      agent_stage: 'coletando_entrega_ou_retirada',
      agent_reply: reply,
      agent_messages: [reply],

      order_data: {
        ...(ctx.order_data || {}),
        order_id: orderId,
        public_code: publicCode
      },

      suggested_addons: addons,
      selected_product: selected
    }
  }
];

// @ts-nocheck

const src = $('CODE: FORMATA CATÁLOGO | S6').first().json || {};

const sentAsMedia = Boolean(
  src.send_catalog_as_media_sequence &&
  Array.isArray(src.catalog_media_options) &&
  src.catalog_media_options.length > 0
);

const finalReply =
  sentAsMedia
    ? (src.catalog_final_message || `Você pode consultar mais opções em nosso catálogo:\n${src.catalog_base || 'https://flordoestudante.vercel.app'}\n\nGostou de alguma dessas?`)
    : (src.catalog_text_fallback_reply || src.agent_reply || 'Gostou de alguma dessas opções?');

return [
  {
    json: {
      ...src,

      image_attempted: sentAsMedia,
      image_sent: sentAsMedia,

      catalog_media_sequence_sent: sentAsMedia,

      /**
       * Importante:
       * daqui para frente o fluxo final deve enviar apenas a mensagem final,
       * pois a introdução e as imagens já foram enviadas diretamente.
       */
      agent_reply: finalReply,
      agent_messages: [finalReply],

      agent_action: 'search_catalog',
      agent_stage: 'apresentando_opcoes'
    }
  }
];

