// @ts-nocheck

const agentCtx = $('CODE: DETECTA ESCOLHA DE PRODUTO | S6').first().json || {};
const result = $json || {};

const ok = result.ok === true;

const orderId =
  result.order_id ||
  agentCtx.order_id ||
  agentCtx.order_data?.order_id ||
  agentCtx.current_order_id ||
  null;

const publicCode =
  result.public_code ||
  agentCtx.public_code ||
  agentCtx.order_data?.public_code ||
  agentCtx.current_order_public_code ||
  null;

let reply =
  agentCtx.agent_reply ||
  'Certo, vamos continuar com o pedido 🌸';

let messages = Array.isArray(agentCtx.agent_messages) && agentCtx.agent_messages.length > 0
  ? agentCtx.agent_messages
  : [reply];

// Não expor erro técnico para o cliente.
if (!ok) {
  messages = messages.map((m) =>
    String(m || '').replace(/\n?_\((houve um problema ao atualizar o pedido, vamos continuar)\)_/gi, '').trim()
  ).filter(Boolean);

  reply = messages.join('\n\n') || reply;
}

return [
  {
    json: {
      ...agentCtx,
      ...result,

      update_order_ok: ok,
      update_order_error: ok ? null : (result.error || 'UPDATE_ORDER_DRAFT_FAILED'),

      order_id: orderId,
      current_order_id: orderId,

      public_code: publicCode,
      current_order_public_code: publicCode,

      agent_action: agentCtx.agent_action || 'update_order_draft',
      agent_stage: agentCtx.agent_stage || 'pedido_em_montagem',

      agent_reply: reply,
      agent_messages: messages,

      order_data: {
        ...(agentCtx.order_data || {}),
        order_id: orderId,
        public_code: publicCode
      }
    }
  }
];

// @ts-nocheck
const agentCtx = $('CODE: DETECTA ESCOLHA DE PRODUTO | S6').first().json || {};
const result = $json || {};
const matchedCount = result.items?.filter(i => i.matched)?.length || 0;
const totalCount = result.item_count || result.items?.length || 0;

return [{
  json: {
    ...agentCtx,
    ...result,
    cart_batch_id: result.batch_id || null,
    cart_matched: matchedCount,
    cart_total: totalCount,
    agent_action: 'parse_whatsapp_cart',
    agent_stage: 'confirmando_pedido',
    agent_reply: matchedCount > 0
      ? (agentCtx.agent_reply || 'Identifiquei os itens do seu carrinho. Posso confirmar o pedido?')
      : (agentCtx.agent_reply || 'Identifiquei os itens do seu carrinho.') + '\n\nPosso confirmar o pedido?'
  }
}];

// @ts-nocheck
const agentCtx = $('CODE: DETECTA ESCOLHA DE PRODUTO | S6').first().json || {};
const result = $json || {};

if (!result.ok) {
  return [{
    json: {
      ...agentCtx,
      ...result,
      agent_reply: (agentCtx.agent_reply || '') + '\n\n_(Houve um erro ao gerar o link de pagamento. Entre em contato conosco.)_',
      checkout_ok: false,
      agent_stage: 'erro'
    }
  }];
}

const checkoutUrl = result.checkout_url || '';
const mpInitPoint = result.mp_init_point || checkoutUrl;
const pix = result.pix || null;

// Mensagem principal: resumo + link
const replyLines = [
  agentCtx.agent_reply || '',
  '',
  mpInitPoint ? `💳 *Link de pagamento:*\n${mpInitPoint}` : (checkoutUrl ? `🔗 ${checkoutUrl}` : ''),
  '',
  pix ? 'Ou, se preferir, pode pagar via *PIX* — envio os dados logo abaixo. 🌸' : 'Após o pagamento, seu pedido será confirmado. Qualquer dúvida, é só chamar! 🌸'
].filter(l => l !== null && l !== undefined && l !== '');

// Mensagem PIX separada (enviada como segunda mensagem pelo próximo nó)
let pixMessage = null;
if (pix) {
  pixMessage = [
    `🔑 *Dados para pagamento via PIX:*`,
    ``,
    `Chave: \`${pix.key}\``,
    `Tipo: ${pix.key_type}`,
    `Titular: ${pix.holder_name}`,
    `Valor: *${pix.amount_formatted}*`,
    ``,
    pix.instructions
  ].join('\n');
}

const mainReply = replyLines.join('\n').replace(/\n{3,}/g, '\n\n').trim();
const outMessages = pixMessage ? [mainReply, pixMessage] : [mainReply];

return [{
  json: {
    ...agentCtx,
    ...result,
    agent_reply: mainReply,
    agent_messages: outMessages,
    pix_message: pixMessage,
    checkout_url: checkoutUrl,
    mp_init_point: mpInitPoint,
    checkout_ok: true,
    agent_action: 'prepare_checkout',
    agent_stage: 'finalizando_pagamento',
    public_code: result.public_code || agentCtx.public_code || null
  }
}];

// @ts-nocheck
const agentCtx = $('CODE: DETECTA ESCOLHA DE PRODUTO | S6').first().json || {};
const result = $json || {};

return [{
  json: {
    ...agentCtx,
    ...result,
    human_lock_set: true,
    agent_action: 'handoff_human',
    agent_stage: 'handoff',
    agent_reply: agentCtx.agent_reply || 'Certo, vou chamar uma pessoa da equipe para te ajudar por aqui 🌸'
  }
}];

// @ts-nocheck

const src = $json || {};
const norm = $('NORMALIZA PAYLOAD WHATSAPP | S6').first().json || {};

const fallbackReply = 'Olá! 🌸 Tive um probleminha técnico por aqui. Pode repetir sua mensagem?';

const agentReply = String(src.agent_reply || fallbackReply).trim();

let messages = [];

if (Array.isArray(src.agent_messages)) {
  messages = src.agent_messages
    .map(m => String(m || '').trim())
    .filter(Boolean);
}

if (messages.length === 0) {
  messages = [agentReply];
}

// Segurança: no máximo 3 mensagens.
messages = messages.slice(0, 3);

// Evita mensagens duplicadas.
const seen = new Set();
messages = messages.filter((m) => {
  const key = m.toLowerCase().trim();
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

return [{
  json: {
    ...src,
    phone_normalized: src.phone_normalized || norm.phone_normalized || '',
    agent_reply: agentReply,
    agent_messages: messages,
    messages_to_send: messages,
    agent_action: src.agent_action || 'ask_info',
    agent_stage: src.agent_stage || src.ctx_stage || 'identificando_necessidade',
    customer_id: src.customer_id || null,
    conversation_id: src.conversation_id || null,
    order_id: src.order_id || src.created_order_id || src.order_data?.order_id || null,
    public_code: src.public_code || src.created_order_code || src.order_data?.public_code || null,
    checkout_url: src.checkout_url || null,
    catalog_results: src.catalog_results || [],
    selected_product: src.selected_product || null,
    suggested_addons: src.suggested_addons || [],
    technical_notes: src.technical_notes || []
  }
}];

// @ts-nocheck

const finalOut = $('CODE: NORMALIZA SAÍDA FINAL | S6').item.json || {};
const norm = $('NORMALIZA PAYLOAD WHATSAPP | S6').item.json || {};

function clean(value) {
  if (value === undefined || value === null) return '';
  return String(value).trim();
}

const fallbackReply = 'Olá! 🌸 Tive um probleminha técnico por aqui. Pode repetir sua mensagem?';

let agentReply = clean(finalOut.agent_reply) || fallbackReply;

let agentMessages = [];

if (Array.isArray(finalOut.agent_messages)) {
  agentMessages = finalOut.agent_messages
    .map(clean)
    .filter(Boolean);
}

if (agentMessages.length === 0) {
  agentMessages = [agentReply];
}

if (agentMessages.length > 3) {
  agentMessages = agentMessages.slice(0, 3);
}

return [
  {
    json: {
      ...finalOut,

      phone_normalized:
        finalOut.phone_normalized ||
        norm.phone_normalized ||
        '',

      agent_reply: agentReply,
      agent_messages: agentMessages,

      order_id:
        finalOut.order_id ||
        finalOut.current_order_id ||
        finalOut.order_data?.order_id ||
        null,

      current_order_id:
        finalOut.current_order_id ||
        finalOut.order_id ||
        finalOut.order_data?.order_id ||
        null,

      current_order_public_code:
        finalOut.current_order_public_code ||
        finalOut.public_code ||
        finalOut.order_data?.public_code ||
        null,

      delay_ms: finalOut.delay_ms || 500
    }
  }
];

