// @ts-nocheck

const src = $json || {};

function clean(value) {
  if (value === undefined || value === null) return '';
  return String(value).trim();
}

const phone = clean(src.phone_normalized);
const fallback = clean(src.agent_reply) || 'Certo 🌸';

let messages = [];

if (Array.isArray(src.agent_messages)) {
  messages = src.agent_messages.map(clean).filter(Boolean);
}

if (messages.length === 0) {
  messages = [fallback];
}

messages = messages.slice(0, 3);

return messages.map((message, index) => ({
  json: {
    ...src,
    phone_normalized: phone,
    agent_reply: message,
    message_index: index,
    messages_total: messages.length,
    delay_ms: index === 0 ? 500 : 1200
  }
}));

